firmware_template.source:
#include "rgb_led.h"
#include <Arduino.h>
#define R_PIN 25
#define G_PIN 26
#define B_PIN 27
void rgb_setup(){ledcAttach(R_PIN,5000,8);ledcAttach(G_PIN,5000,8);ledcAttach(B_PIN,5000,8);Serial.println("[rgb] OK");}
void rgb_set(uint8_t r,uint8_t g,uint8_t b){ledcWrite(R_PIN,r);ledcWrite(G_PIN,g);ledcWrite(B_PIN,b);}
void rgb_off(){rgb_set(0,0,0);}
